2072     updatePostIncRangeInfo(NarrowDef, NarrowUser, NarrowDefRange);
2073   };
2074 
2075   auto UpdateRangeFromGuards = [&](Instruction *Ctx) {
2076     if (!HasGuards)
2077       return;
2078 
2079     for (Instruction &I : make_range(Ctx->getIterator().getReverse(),
2080                                      Ctx->getParent()->rend())) {
2081       Value *C = nullptr;
2082       if (match(&I, m_Intrinsic<Intrinsic::experimental_guard>(m_Value(C))))
2083         UpdateRangeFromCondition(C, /*TrueDest=*/true);
2084     }
2085   };
2086 
2087   UpdateRangeFromGuards(NarrowUser);
2088 
2089   BasicBlock *NarrowUserBB = NarrowUser->getParent();
2090   // If NarrowUserBB is statically unreachable asking dominator queries may
2091   // yield surprising results. (e.g. the block may not have a dom tree node)
2092   if (!DT->isReachableFromEntry(NarrowUserBB))
2093     return;
2094 
2095   for (auto *DTB = (*DT)[NarrowUserBB]->getIDom();
2096        L->contains(DTB->getBlock());
